// TODO: Unit tests for JobStateService.
import { TestBed, fakeAsync, tick } from '@angular/core/testing';
import { of, throwError } from 'rxjs';

import { JobStateService } from './job-state.service';
import { JobSummaryDataService } from '../job-summary.data.service';
import { DtoJobSummaryDataModel } from '../models/dto-job-summary.data.model';

describe('JobStateService', () => {
  let service: JobStateService;
  let dataService: jasmine.SpyObj<JobSummaryDataService>;

  const mockDtos: DtoJobSummaryDataModel.Item[] = [
    {
      job_id: 'job-001',
      pad_name: 'Permian Basin Alpha',
      status_name: 'Active',
      region_name: 'Permian',
      plan_start_date: '2025-03-01',
      days_planned: 45,
      percent_complete: 62
    },
    {
      job_id: 'job-002',
      pad_name: 'Eagle Ford Beta',
      status_name: 'Planned',
      region_name: 'Eagle Ford',
      plan_start_date: '2025-04-15',
      days_planned: 30,
      percent_complete: 0
    },
    {
      job_id: 'job-003',
      pad_name: 'Permian Basin Delta',
      status_name: 'Complete',
      region_name: 'Permian',
      plan_start_date: '2025-03-20',
      days_planned: 60,
      percent_complete: 100
    }
  ];

  beforeEach(() => {
    dataService = jasmine.createSpyObj<JobSummaryDataService>(
      'JobSummaryDataService',
      ['getJobs', 'getJobById']
    );

    TestBed.configureTestingModule({
      providers: [
        JobStateService,
        {
          provide: JobSummaryDataService,
          useValue: dataService
        }
      ]
    });

    service = TestBed.inject(JobStateService);
  });

  it('loads jobs and maps DTOs into the domain model', fakeAsync(() => {
    dataService.getJobs.and.returnValue(of(mockDtos));

    service.loadJobs();
    tick();

    expect(service.jobs()).toEqual([
      {
        jobId: 'job-001',
        padName: 'Permian Basin Alpha',
        statusName: 'Active',
        regionName: 'Permian',
        planStartDate: '2025-03-01',
        daysPlanned: 45,
        percentComplete: 62
      },
      {
        jobId: 'job-002',
        padName: 'Eagle Ford Beta',
        statusName: 'Planned',
        regionName: 'Eagle Ford',
        planStartDate: '2025-04-15',
        daysPlanned: 30,
        percentComplete: 0
      },
      {
        jobId: 'job-003',
        padName: 'Permian Basin Delta',
        statusName: 'Complete',
        regionName: 'Permian',
        planStartDate: '2025-03-20',
        daysPlanned: 60,
        percentComplete: 100
      }
    ]);

    expect(service.error()).toBeNull();
    expect(service.loading()).toBeFalse();
  }));

  it('filters jobs by selected region', fakeAsync(() => {
    dataService.getJobs.and.returnValue(of(mockDtos));

    service.loadJobs();
    tick();

    service.updateRegion('Permian');

    expect(service.filteredJobs().length).toBe(2);
    expect(service.filteredJobs().every(job => job.regionName === 'Permian')).toBeTrue();
  }));

  it('filters jobs by selected status', fakeAsync(() => {
    dataService.getJobs.and.returnValue(of(mockDtos));

    service.loadJobs();
    tick();

    service.updateStatus('Planned');

    expect(service.filteredJobs()).toEqual([
      {
        jobId: 'job-002',
        padName: 'Eagle Ford Beta',
        statusName: 'Planned',
        regionName: 'Eagle Ford',
        planStartDate: '2025-04-15',
        daysPlanned: 30,
        percentComplete: 0
      }
    ]);
  }));

  it('filters jobs by region and status together', fakeAsync(() => {
    dataService.getJobs.and.returnValue(of(mockDtos));

    service.loadJobs();
    tick();

    service.updateRegion('Permian');
    service.updateStatus('Complete');

    expect(service.filteredJobs()).toEqual([
      {
        jobId: 'job-003',
        padName: 'Permian Basin Delta',
        statusName: 'Complete',
        regionName: 'Permian',
        planStartDate: '2025-03-20',
        daysPlanned: 60,
        percentComplete: 100
      }
    ]);
  }));

  it('clears filters', fakeAsync(() => {
    dataService.getJobs.and.returnValue(of(mockDtos));

    service.loadJobs();
    tick();

    service.updateRegion('Permian');
    service.updateStatus('Complete');

    expect(service.filteredJobs().length).toBe(1);

    service.resetFilters();

    expect(service.selectedRegion()).toBeNull();
    expect(service.selectedStatus()).toBeNull();
    expect(service.filteredJobs().length).toBe(3);
  }));

  it('exposes available regions and statuses', fakeAsync(() => {
    dataService.getJobs.and.returnValue(of(mockDtos));

    service.loadJobs();
    tick();

    expect(service.availableRegions()).toEqual(['Eagle Ford', 'Permian']);
    expect(service.availableStatuses()).toEqual(['Active', 'Complete', 'Planned']);
  }));

  it('stores an error message when loading jobs fails', fakeAsync(() => {
    dataService.getJobs.and.returnValue(
      throwError(() => new Error('Failed to load jobs. Please try again.'))
    );

    service.loadJobs();
    tick();

    expect(service.error()).toBe('Failed to load jobs. Please try again.');
    expect(service.jobs()).toEqual([]);
    expect(service.loading()).toBeFalse();
  }));

  it('retries loading jobs after an error', fakeAsync(() => {
    dataService.getJobs.and.returnValues(
      throwError(() => new Error('Failed to load jobs. Please try again.')),
      of(mockDtos)
    );

    service.loadJobs();
    tick();

    expect(service.error()).toBe('Failed to load jobs. Please try again.');
    expect(service.jobs()).toEqual([]);

    service.retryLoad();
    tick();

    expect(dataService.getJobs).toHaveBeenCalledTimes(2);
    expect(service.error()).toBeNull();
    expect(service.jobs().length).toBe(3);
  }));
});
